{
  "resources": [
    {
      "name": "Sunrise Navigation Center – Sunrise Hub (Showers & Day Services)",
      "addresses": [
        "4430 Menchaca Rd, Austin, TX 78745"
      ],
      "phones": [
        "512-522-1097",
        "512-368-2685"
      ],
      "emails": [
        "navigation@sunriseaustin.org",
        "hotline@sunriseaustin.org"
      ],
      "website": "https://sunrisenavigationcenter.org/get-help",
      "description": "Low-barrier day center for people experiencing homelessness in Austin/Travis County. The Sunrise Hub offers showers (typically 9:00 a.m.–12:00 p.m.), restrooms, meals, hygiene items, device charging, Wi‑Fi, computer lab help, mail services, and housing navigation. Clients usually line up before opening; services are first‑come, first‑served. No insurance or ID required for basic services.",
      "justification": "Best first referral for a homeless client needing showers and restrooms in Austin. It is specifically designed for unsheltered individuals, is centrally located in South Austin, and clearly lists showers and bathrooms as daily services.",
      "referral_type": "external"
    },
    {
      "name": "ARCH – Austin Resource Center for the Homeless (Day Services & Restrooms)",
      "addresses": [
        "500 E 7th St, Austin, TX 78701"
      ],
      "phones": [
        "512-881-8951"
      ],
      "emails": [],
      "website": "https://www.austintexas.gov/department/shelters",
      "description": "City‑owned emergency shelter for adult men in downtown Austin operated by Endeavors. While overnight beds are accessed only via the City’s shelter waitlist, the ARCH building also functions as a key downtown access point for basic needs and services. Clients can typically access indoor restrooms and connect with staff for navigation, healthcare, and other supports. Call or have client present during daytime hours to confirm current access to showers and bathroom facilities for non‑residents.",
      "justification": "Central downtown location frequently used by people experiencing homelessness for basic needs and navigation. Appropriate for unsheltered adult men who may be near downtown and need restrooms and possible shower access.",
      "referral_type": "government"
    },
    {
      "name": "Trinity Center Austin (Downtown – Day Shelter & Restrooms)",
      "addresses": [
        "304 E 7th St, Austin, TX 78701"
      ],
      "phones": [
        "512-610-3551"
      ],
      "emails": [],
      "website": "https://www.trinitycenteraustin.org/",
      "description": "Faith‑based day resource center located behind St. David’s Episcopal Church serving adults experiencing homelessness in downtown Austin. Provides daytime hospitality including indoor restrooms, basic needs support (mail, clothing, limited financial help via partners), and resource navigation. Hours and specific services vary; check their website or call for current drop‑in times and whether showers are available on‑site or via partner agencies.",
      "justification": "Very close to the ARCH and other downtown services, commonly used by homeless adults for daytime restrooms and basic needs. Good option if the client spends time around downtown Austin.",
      "referral_type": "external"
    }
  ]
}

