{
  "resources": [
    {
      "name": "CapMetro – Service During Extreme Weather & Cold Weather Shelters",
      "addresses": [
        "CapMetro Transit Store, 1718 Guadalupe St, Austin, TX 78701",
        "One Texas Center (Cold Weather Shelter Check‑in), 505 Barton Springs Rd, Austin, TX 78704"
      ],
      "phones": [
        "512-474-1200",
        "512-972-5055",
        "311"
      ],
      "emails": [],
      "website": "https://www.capmetro.org/weather",
      "description": "CapMetro coordinates closely with the City of Austin during extreme cold. When the City activates Cold Weather Shelters (generally when overnight temps are forecast at or below about 35°F), individuals must first check in at One Texas Center, 505 Barton Springs Rd, between 6–8 p.m. (hours can expand to 2–8 p.m. during major events). Multiple regular bus routes (1, 7, 10, 20, 30, 105, 142, 801) serve this location, and people who cannot pay fare are still allowed to ride to shelter check‑in. From there, CapMetro buses transport registered guests to overnight cold weather shelters; locations are not published for safety and capacity reasons. During major winter events, CapMetro may suspend regular bus/rail service early but will provide limited or complimentary trips specifically to warming centers and shelter embarkation points until service ends (often around 4 p.m.). Riders should use the CapMetro GO Line, the CapMetro weather page, or city alerts for up‑to‑date changes in routes and operating hours.",
      "justification": "Client needs CapMetro cold weather information. This resource explains how CapMetro adjusts service during winter storms, how riders can reach cold weather shelters, and how no‑fare rides to One Texas Center work, using current City of Austin and CapMetro guidance.",
      "referral_type": "government"
    },
    {
      "name": "City of Austin – Cold Weather Shelters & Warming Centers (Austin HSEM/AHSO)",
      "addresses": [
        "One Texas Center (Shelter Registration), 505 Barton Springs Rd, Austin, TX 78704"
      ],
      "phones": [
        "512-972-5055"
      ],
      "emails": [],
      "website": "https://www.austintexas.gov/alerts",
      "description": "The City of Austin’s Homeless Strategy Office and Office of Homeland Security & Emergency Management manage Cold Weather Shelters and related transportation. Cold Weather Shelters typically activate when forecasted overnight temperatures at Camp Mabry are expected to reach 35°F or below. Anyone needing a warm, safe place overnight can access shelters, with priority use by people experiencing homelessness. Registration is usually 6–8 p.m. at One Texas Center, 505 Barton Springs Rd; during major winter storms, registration may run 2–8 p.m. CapMetro buses transport registered guests from One Texas Center to shelter sites at no cost. For current activation status, intake hours, and any transportation changes, individuals should call the Cold Weather Shelter Info Line at 512‑972‑5055 or check the City’s Alerts page. During cold events, many Parks and Recreation and Austin Public Library locations also serve as daytime Warming Centers during normal or extended hours, and a Warming Centers map is posted on the Alerts site.",
      "justification": "Client specifically requested cold weather information connected to CapMetro. The City of Austin manages shelter activation, intake site, and coordinates with CapMetro for transportation; this is the authoritative local source case managers should use.",
      "referral_type": "government"
    }
  ]
}

{
  "resources": [
    {
      "name": "CapMetro – Free Rides to Austin Cold Weather Shelters & Warming Centers",
      "addresses": [
        "Service area: Austin and surrounding communities in Travis County, TX"
      ],
      "phones": [
        "512-474-1200",
        "512-389-7454"
      ],
      "emails": [],
      "website": "https://www.capmetro.org",
      "description": "During activated Cold Weather Shelter or Warming Center operations in Austin/Travis County, CapMetro coordinates with the Austin-Travis County Emergency Operations Center to provide transportation support. When the City opens Cold Weather Shelters, people can register nightly between 6 p.m. and 8 p.m. at One Texas Center, 505 Barton Springs Rd. CapMetro bus routes 1, 7, 10, 20, 30, 105, 142, and 801 serve this intake site. Riders who are going to a Cold Weather Shelter or Warming Center and do not have money for fare are still allowed to board and will be transported to One Texas Center or directly to designated warming sites when emergency operations are active. In some severe winter events, CapMetro suspends regular service and uses buses only for emergency trips such as transportation to warming centers, shelters, and critical medical appointments, with fares waived for these emergency trips.",
      "justification": "Client is asking specifically for CapMetro cold weather information. CapMetro partners with the City of Austin during winter weather to provide no-fare rides for people traveling to Cold Weather Shelters and Warming Centers, and multiple official City and CapMetro communications confirm that riders without fare are still allowed to board when traveling to these locations.",
      "referral_type": "external"
    },
    {
      "name": "City of Austin Cold Weather Shelters – Intake & Info (includes CapMetro access details)",
      "addresses": [
        "One Texas Center – Cold Weather Shelter Intake: 505 Barton Springs Rd, Austin, TX 78704"
      ],
      "phones": [
        "512-972-5055",
        "311"
      ],
      "emails": [],
      "website": "https://www.austintexas.gov/alerts",
      "description": "The City of Austin’s Cold Weather Shelters open when overnight temperatures are forecast at or below 35°F (or 32°F with wind chill/precipitation). The Homeless Strategy Office announces activation by 9 a.m. the day of activation. Registration for overnight shelter is 6–8 p.m. at One Texas Center (OTC), 505 Barton Springs Rd. CapMetro bus routes 1, 7, 10, 20, 30, 105, 142, and 801 serve OTC. People going to a Cold Weather Shelter who cannot pay fare will still be allowed to ride CapMetro buses to the intake site and then be transported by CapMetro from OTC to shelter locations. Cold Weather Shelters are primarily used by people experiencing homelessness but are open to anyone needing a warm place overnight. Clients can call the Cold Weather Shelter Hotline at 512-972-5055 or check austintexas.gov/alerts for current activation status, shelter access instructions, and related CapMetro transportation updates.",
      "justification": "This is the primary official source for cold weather shelter operations and explicitly describes how CapMetro provides access, including that routes serving One Texas Center are available and that riders without fare will still be given a ride when traveling to cold weather shelters.",
      "referral_type": "government"
    }
  ]
}

